changeSet.sql:
CREATE OR REPLACE FUNCTION prevent_evidence_record_update()
RETURNS TRIGGER AS $$
BEGIN
    RAISE EXCEPTION 'UPDATE on evidence_record is not allowed — records are immutable';
END;
$$ LANGUAGE plpgsql;

CREATE OR REPLACE FUNCTION prevent_evidence_record_delete()
RETURNS TRIGGER AS $$
BEGIN
    RAISE EXCEPTION 'DELETE on evidence_record is not allowed — records are immutable';
END;
$$ LANGUAGE plpgsql;

rollback.sql:
DROP TRIGGER IF EXISTS trg_evidence_record_no_update ON evidence_record;
DROP TRIGGER IF EXISTS trg_evidence_record_no_delete ON evidence_record;
DROP FUNCTION IF EXISTS prevent_evidence_record_update();
DROP FUNCTION IF EXISTS prevent_evidence_record_delete();
